---@class LSecretBubble:LBubbleBase
local LSecretBubble = LxClass("LSecretBubble", LBubbleBase)
local typeOfTextMesh = typeof(CS.TextMeshPro)
local BuildingClick = CS.BuildingClick
local Tweening = DG.Tweening


function LSecretBubble:LSecretBubble(prefabName)
    self._seqCom = SequenceCom:New()

    self._prefabName = prefabName or "SecretBubble"
end

function LSecretBubble:GetPrefabPath()
    local path = "UI/Prefabs/Com"
    local fullPath = string.format("%s/%s",path,self._prefabName)

    return fullPath,path,self._prefabName
end

function LSecretBubble:OnSetBubbleContent(item,itemdata)
    local text = CS.FindTrans(item,"UIText")
    local com = text:GetComponent(typeOfTextMesh)
    if com then
        --com.text = itemdata.text
        self:SetXTextMeshProContent(text, itemdata.text)
        local renderer = com.renderer
        renderer.sortingLayerName = "Object"
        renderer.sortingOrder = 2
    end

    self:SetFollow(itemdata.followTran,itemdata.offset)
    local img = CS.FindTrans(item,"bubble")
    local comp = BuildingClick.Get(img.gameObject)
    if comp then
        comp.ClickDelegate = itemdata.callBack
    end

    local seq = self._seqCom:CreateSeq("scale")
    item.localScale = Vector3.one
    local tween = item:DOScale(Vector3.one*0.95,1)
    seq:Append(tween)
    seq:SetLoops(-1,Tweening.LoopType.Yoyo)
    seq:PlayForward()
end

function LSecretBubble:RefreshText(str)
    if not self:IsBubbleTranValid() then return end

    local text = CS.FindTrans(self._bubbleTran,"UIText")
    local com = text:GetComponent(typeOfTextMesh)
    if com then
        com.text = str
    end
end


return LSecretBubble